Reverse Proxy

Concepto
┌─────────────────────────────────────────────────────────────────┐
│                    REVERSE PROXY NGINX                          │
├─────────────────────────────────────────────────────────────────┤
│                                                                  │
│   INTERNET                  NGINX              BACKEND          │
│  ┌─────────┐            ┌─────────┐        ┌─────────┐          │
│  │ cliente │ ──────────&gt; │ :80/:443│ ──────&gt; │ :3000   │          │
│  │         │  request    │ proxy   │         │ (app)   │          │
│  └─────────┘            └─────────┘        └─────────┘          │
│                                                                  │
│   NGINX: load balancer, SSL terminator, cache, logs centralizados│
│   BACKEND: Node, Python, Go, Java - solo localhost              │
└─────────────────────────────────────────────────────────────────┘


Reverse Proxy a Aplicación


BASH

$ sudo tee /etc/nginx/sites-available/api-proxy.conf &lt;&lt;'EOF'
server {
    listen 80;
    server_name api.example.com;

    # Proxy a backend
    location / {
        proxy_pass http://127.0.0.1:3000;

        # Headers esenciales
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # Timeouts
        proxy_connect_timeout 60s;
        proxy_send_timeout 60s;
        proxy_read_timeout 60s;
    }

    # Health check endpoint
    location /health {
        proxy_pass http://127.0.0.1:3000/health;
        access_log off;
    }
}
EOF

$ sudo ln -sf /etc/nginx/sites-available/api-proxy.conf /etc/nginx/sites-enabled/
$ sudo nginx -t && sudo systemctl reload nginx


1

Proxy completo: Headers, timeouts, health check




Proxy a Múltiples Backends (Load Balancing)


BASH

$ sudo tee /etc/nginx/sites-available/loadbalancer.conf &lt;&lt;'EOF'
upstream backend {
    least_conn;  # Menos conexiones

    server 10.0.1.11:3000 weight=5;
    server 10.0.1.12:3000 weight=3;
    server 10.0.1.13:3000 weight=2;
}

server {
    listen 80;
    server_name api.example.com;

    location / {
        proxy_pass http://backend;

        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}
EOF

$ sudo ln -sf /etc/nginx/sites-available/loadbalancer.conf /etc/nginx/sites-enabled/
$ sudo nginx -t && sudo systemctl reload nginx


1

Load balancing: round-robin, least_conn, IP hash




